/*
 * Bad Block Management - Sector Sparing Implementation
 * 
 * This program simulates how modern disk controllers handle bad blocks
 * using sector sparing (also known as sector forwarding or remapping).
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define SECTOR_SIZE 512
#define TOTAL_SECTORS 100
#define TOTAL_SPARE_SECTORS 5
#define ECC_SIZE 32

/* Sector structure representing a physical disk sector */
typedef struct {
 unsigned int sector_number; /* Logical sector number */
 unsigned int cylinder; /* Cylinder number */
 unsigned int head; /* Head number */
 unsigned int track; /* Track number */
 unsigned char data[SECTOR_SIZE]; /* Sector data */
 unsigned char ecc[ECC_SIZE]; /* Error-Correcting Code */
 bool is_spare; /* Is this a spare sector? */
 bool is_bad; /* Is this sector marked bad? */
 unsigned int remapped_to; /* If remapped, sector number it maps to */
} Sector;

/* Disk controller state */
typedef struct {
 Sector sectors[TOTAL_SECTORS];
 Sector spare_sectors[TOTAL_SPARE_SECTORS];
 unsigned int next_spare_index;
 unsigned int bad_block_count;
} DiskController;

/* Initialize the disk with sectors and spare areas */
void initialize_disk(DiskController *controller) {
 printf("Initializing disk with %d sectors and %d spare sectors...\n", 
 TOTAL_SECTORS, TOTAL_SPARE_SECTORS);

 controller->next_spare_index = 0;
 controller->bad_block_count = 0;

 /* Initialize regular sectors */
 for (unsigned int i = 0; i < TOTAL_SECTORS; i++) {
 controller->sectors[i].sector_number = i;
 controller->sectors[i].cylinder = i / 100;
 controller->sectors[i].head = (i / 10) % 10;
 controller->sectors[i].track = i % 10;
 controller->sectors[i].is_spare = false;
 controller->sectors[i].is_bad = false;
 controller->sectors[i].remapped_to = 0;

 /* Initialize with dummy data */
 memset(controller->sectors[i].data, 0, SECTOR_SIZE);
 memset(controller->sectors[i].ecc, 0, ECC_SIZE);
 }

 /* Initialize spare sectors */
 for (unsigned int i = 0; i < TOTAL_SPARE_SECTORS; i++) {
 controller->spare_sectors[i].sector_number = TOTAL_SECTORS + i;
 controller->spare_sectors[i].is_spare = true;
 controller->spare_sectors[i].is_bad = false;
 controller->spare_sectors[i].remapped_to = 0;
 memset(controller->spare_sectors[i].data, 0, SECTOR_SIZE);
 memset(controller->spare_sectors[i].ecc, 0, ECC_SIZE);
 }

 printf("Disk initialization complete.\n\n");
}

/* Simulate marking a sector as bad (during format or runtime) */
void mark_bad_sector(DiskController *controller, unsigned int sector_num) {
 if (sector_num >= TOTAL_SECTORS) {
 printf("Error: Invalid sector number %u\n", sector_num);
 return;
 }

 controller->sectors[sector_num].is_bad = true;
 controller->bad_block_count++;

 printf("Marked sector %u as BAD\n", sector_num);
}

/* Perform sector sparing - remap bad sector to a spare */
bool sector_sparing(DiskController *controller, unsigned int bad_sector) {
 if (controller->next_spare_index >= TOTAL_SPARE_SECTORS) {
 printf("Error: No more spare sectors available!\n");
 return false;
 }

 if (!controller->sectors[bad_sector].is_bad) {
 printf("Error: Sector %u is not marked as bad\n", bad_sector);
 return false;
 }

 /* Get the next available spare sector */
 unsigned int spare_idx = controller->next_spare_index;
 controller->next_spare_index++;

 /* Copy data from bad sector to spare (if any existed) */
 memcpy(controller->spare_sectors[spare_idx].data, 
 controller->sectors[bad_sector].data, SECTOR_SIZE);

 /* Update remapping information */
 controller->sectors[bad_sector].remapped_to = TOTAL_SECTORS + spare_idx;
 controller->spare_sectors[spare_idx].remapped_to = bad_sector;

 printf("SECTOR SPARING: Bad sector %u remapped to spare sector %u\n",
 bad_sector, TOTAL_SECTORS + spare_idx);

 return true;
}

/* Sector slipping - shift sectors to fill the gap */
void sector_slipping(DiskController *controller, unsigned int bad_sector) {
 printf("\n--- SECTOR SLIPPING for bad sector %u ---\n", bad_sector);

 if (bad_sector >= TOTAL_SECTORS - 1) {
 printf("Cannot slip: bad sector is at the end\n");
 return;
 }

 /* Copy bad sector data (if any) to swap buffer */
 unsigned char temp_data[SECTOR_SIZE];
 memcpy(temp_data, controller->sectors[bad_sector].data, SECTOR_SIZE);

 /* Slip all subsequent sectors forward by one position */
 for (unsigned int i = bad_sector; i < TOTAL_SECTORS - 1; i++) {
 memcpy(controller->sectors[i].data, 
 controller->sectors[i + 1].data, SECTOR_SIZE);
 controller->sectors[i].sector_number = i;
 }

 /* Put original bad sector data at the last position (using last spare) */
 unsigned int last_idx = TOTAL_SECTORS - 1;
 memcpy(controller->sectors[last_idx].data, temp_data, SECTOR_SIZE);
 controller->sectors[last_idx].sector_number = last_idx;

 /* Mark the originally bad sector as remapped */
 controller->sectors[bad_sector].is_bad = true;
 controller->sectors[bad_sector].remapped_to = last_idx;

 printf("After slipping: sectors %u-%u shifted left by 1\n", 
 bad_sector + 1, last_idx);
 printf("Logical sector %u now maps to physical sector %u\n", 
 bad_sector, last_idx);
}

/* Read a sector - handles remapping transparently */
bool read_sector(DiskController *controller, unsigned int logical_sector, 
 unsigned char *buffer) {
 if (logical_sector >= TOTAL_SECTORS) {
 printf("Error: Invalid logical sector %u\n", logical_sector);
 return false;
 }

 Sector *s = &controller->sectors[logical_sector];

 /* Check if this sector has been remapped */
 if (s->is_bad && s->remapped_to != 0) {
 unsigned int physical = s->remapped_to;
 printf("READ: Remapping logical sector %u -> physical sector %u\n",
 logical_sector, physical);

 if (physical >= TOTAL_SECTORS) {
 /* Remapped to spare sector */
 memcpy(buffer, 
 controller->spare_sectors[physical - TOTAL_SECTORS].data,
 SECTOR_SIZE);
 } else {
 memcpy(buffer, controller->sectors[physical].data, SECTOR_SIZE);
 }
 } else {
 /* Normal read */
 memcpy(buffer, s->data, SECTOR_SIZE);
 }

 return true;
}

/* Display disk status */
void display_disk_status(DiskController *controller) {
 printf("\n========== DISK STATUS ==========\n");
 printf("Total sectors: %d\n", TOTAL_SECTORS);
 printf("Total spare sectors: %d\n", TOTAL_SPARE_SECTORS);
 printf("Spare sectors used: %d\n", controller->next_spare_index);
 printf("Spare sectors available: %d\n", 
 TOTAL_SPARE_SECTORS - controller->next_spare_index);
 printf("Bad block count: %d\n", controller->bad_block_count);

 printf("\nBad sectors and their remapping:\n");
 for (unsigned int i = 0; i < TOTAL_SECTORS; i++) {
 if (controller->sectors[i].is_bad) {
 printf(" Logical sector %u ", i);
 if (controller->sectors[i].remapped_to != 0) {
 printf("-> physical sector %u\n", 
 controller->sectors[i].remapped_to);
 } else {
 printf("(no remapping)\n");
 }
 }
 }
 printf("================================\n\n");
}

/* Simulate ECC error detection and correction */
void simulate_ecc_check(unsigned int sector_num) {
 printf("ECC Check: Verifying data integrity for sector %u\n", sector_num);
 /* In real hardware, ECC would be calculated and compared here */
 printf("ECC: Data integrity OK\n");
}

int main() {
 printf("========== BAD BLOCK MANAGEMENT DEMO ==========\n\n");

 /* Initialize disk controller */
 DiskController controller;
 initialize_disk(&controller);

 /* Simulate finding bad sectors during format */
 printf("--- Simulating Format: Scanning for Bad Sectors ---\n");
 mark_bad_sector(&controller, 15);
 mark_bad_sector(&controller, 42);
 mark_bad_sector(&controller, 78);

 /* Apply sector sparing to handle bad sectors */
 printf("\n--- Applying Sector Sparing ---\n");
 sector_sparing(&controller, 15);
 sector_sparing(&controller, 42);
 sector_sparing(&controller, 78);

 /* Display current status */
 display_disk_status(&controller);

 /* Demonstrate transparent read with remapping */
 printf("--- Demonstrating Transparent Read ---\n");
 unsigned char buffer[SECTOR_SIZE];

 /* Read from a bad sector - controller transparently remaps */
 read_sector(&controller, 15, buffer);
 simulate_ecc_check(15);

 /* Demonstrate sector slipping */
 printf("\n--- Demonstrating Sector Slipping ---\n");
 mark_bad_sector(&controller, 25);
 sector_slipping(&controller, 25);

 printf("\n========== DEMO COMPLETE ==========\n");

 return 0;
}
